import{c as l,Z as a,Q as u,j as d,g as t,n as o,o as n,m as s,av as c}from"./chunks/framework.BPKcPtvA.js";const k=JSON.parse('{"title":"Buy & sell autonomously","description":"With a Scoped session live, ask HavenBot to buy and sell in plain language — it executes on-chain with no per-trade confirmation.","frontmatter":{"title":"Buy & sell autonomously","description":"With a Scoped session live, ask HavenBot to buy and sell in plain language — it executes on-chain with no per-trade confirmation."},"headers":[],"relativePath":"guide/agent/autonomous.md","filePath":"guide/agent/autonomous.md","lastUpdated":1780218602000}'),h={name:"guide/agent/autonomous.md"};function m(p,e,g,y,f,b){const i=a("TaskMeta"),r=a("ExpectedResult");return u(),d("div",null,[e[1]||(e[1]=t("h1",{id:"buy-sell-autonomously",tabindex:"-1"},[o("Buy & sell autonomously "),t("a",{class:"header-anchor",href:"#buy-sell-autonomously","aria-label":'Permalink to "Buy & sell autonomously"'},"​")],-1)),n(i,{time:"~4 min",role:"Any signed-in user",needs:"A Scoped session armed (H3)"}),e[2]||(e[2]=s('<blockquote><p><strong>What you&#39;ll do:</strong> with a live Scoped session, tell HavenBot to <strong>buy</strong> and then <strong>sell</strong> in plain language and watch each trade land on-chain — no confirmation modal.</p></blockquote><h2 id="before-you-begin" tabindex="-1">Before you begin <a class="header-anchor" href="#before-you-begin" aria-label="Permalink to &quot;Before you begin&quot;">​</a></h2><div class="info custom-block"><p class="custom-block-title">Requires a Scoped session</p><p>This flow only runs once you&#39;ve armed a <strong>Scoped</strong> session — see <a href="/guide/agent/set-tier">H3 · Arm Scoped autonomy</a>. Without one, the same requests fall back to a dashboard deep-link you approve with your passkey.</p></div><h2 id="buy-—-no-confirmation" tabindex="-1">Buy — no confirmation <a class="header-anchor" href="#buy-—-no-confirmation" aria-label="Permalink to &quot;Buy — no confirmation&quot;">​</a></h2><ol><li>Open <strong>Agent</strong> (<code>/agent</code>).</li><li>Type a plain-language buy, e.g. <strong>&quot;Buy $5 of CETES.&quot;</strong></li><li>HavenBot executes it <strong>immediately</strong> — no confirmation card, because your Scoped session authorizes trades up to your per-trade cap. After ~30–60s (gas is sponsored) it replies with a <strong>transaction hash</strong>.</li></ol><h2 id="sell-—-no-confirmation" tabindex="-1">Sell — no confirmation <a class="header-anchor" href="#sell-—-no-confirmation" aria-label="Permalink to &quot;Sell — no confirmation&quot;">​</a></h2><ol><li>In the same chat, type <strong>&quot;Sell 2 shares of CETES.&quot;</strong></li><li>HavenBot submits the sell autonomously and returns a <strong>tx hash</strong>. A sell within the token&#39;s per-epoch instant cap settles immediately; a larger sell is queued and settles in a later epoch (claim it later — see <a href="/guide/investor/redemption-queue">I9 · Redemption-queue claim</a>).</li></ol><div class="tip custom-block"><p class="custom-block-title">Advisory vs Scoped — the difference you just saw</p><p>On <strong>Advisory</strong> (or with no session), every buy/sell surfaces a confirmation you approve with your passkey. With a <strong>Scoped</strong> session live, HavenBot signs within your cap and TTL — that&#39;s why neither trade above asked you to confirm.</p></div><h2 id="more-it-can-do-autonomously" tabindex="-1">More it can do autonomously <a class="header-anchor" href="#more-it-can-do-autonomously" aria-label="Permalink to &quot;More it can do autonomously&quot;">​</a></h2><ul><li><strong>Auto-reinvest</strong> — HavenBot can automatically claim matured yield and buy more of the same token (opt-in on the policy page).</li><li><strong>Rebalance to targets</strong> — ask HavenBot to <em>&quot;rebalance my portfolio to these targets&quot;</em>. It uses the <strong>Auto-rebalance</strong> panel on <code>/portfolio</code>, then executes <strong>one atomic transaction</strong> (sells before buys) within your Scoped session.</li></ul><h2 id="verify" tabindex="-1">Verify <a class="header-anchor" href="#verify" aria-label="Permalink to &quot;Verify&quot;">​</a></h2><ol><li>Open <a href="/guide/investor/activity">Activity</a>, or ask HavenBot <em>&quot;show my recent activity&quot;</em>.</li><li>Your buy and sell appear as settled rows within ~30–60s.</li></ol><div class="tip custom-block"><p class="custom-block-title">Stop it anytime — just ask</p><p>To halt autonomous execution, tell HavenBot <em>&quot;pause my agent&quot;</em> — that blocks every write instantly. You can also revoke the session from the dashboard or via Telegram. To resume, pick a tier again on the dashboard and confirm with your passkey.</p></div><h2 id="expected-result" tabindex="-1">Expected result <a class="header-anchor" href="#expected-result" aria-label="Permalink to &quot;Expected result&quot;">​</a></h2>',14)),n(r,null,{default:c(()=>[...e[0]||(e[0]=[o(" Both the buy and the sell execute ",-1),t("strong",null,"without a per-action prompt",-1),o(" and return a ",-1),t("strong",null,"tx hash",-1),o(". After ~30–60s they appear in ",-1),t("a",{href:"/guide/investor/activity"},"Activity",-1),o(". ",-1)])]),_:1}),e[3]||(e[3]=s('<h2 id="if-something-goes-wrong" tabindex="-1">If something goes wrong <a class="header-anchor" href="#if-something-goes-wrong" aria-label="Permalink to &quot;If something goes wrong&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Symptom</th><th>Fix</th></tr></thead><tbody><tr><td>HavenBot returns a deep-link instead of trading</td><td>No live Scoped session — arm one in <a href="/guide/agent/set-tier">H3 · Arm Scoped autonomy</a>.</td></tr><tr><td>A sell was queued, not instant</td><td>The amount exceeded the per-epoch instant cap — settle the queued portion later (<a href="/guide/investor/redemption-queue">I9</a>).</td></tr><tr><td>HavenBot asks your passkey for a deposit/withdraw</td><td>Expected — converting USDC ↔ mhUSDC always uses a dashboard deep-link, never autonomous submission.</td></tr><tr><td>You want to stop everything now</td><td>Ask HavenBot <em>&quot;pause my agent&quot;</em> — it blocks every write instantly. You can also revoke the session from the dashboard or via Telegram.</td></tr></tbody></table><p>→ Next: <a href="/guide/mcp/arm-scoped">Arm Scoped autonomy on the dashboard (MCP)</a></p>',3))])}const q=l(h,[["render",m]]);export{k as __pageData,q as default};
